import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/launcher-screen.B4Y3DSWp.js";const o=JSON.parse(`{"title":"安裝 Fabric","description":"安裝 Fabric 的逐步指南。","frontmatter":{"title":"安裝 Fabric","description":"安裝 Fabric 的逐步指南。","authors":["IMB11","Benonardo","modmuss50"],"files":[]},"headers":[],"relativePath":"zh_tw/1.21.4/players/installing-fabric.md","filePath":"versions/1.21.4/translated/zh_tw/players/installing-fabric.md","lastUpdated":1760721669000}`);var s={name:`zh_tw/1.21.4/players/installing-fabric.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">安裝 Fabric <a class="header-anchor" href="#h1" aria-label="Permalink to “安裝 Fabric”">​</a></h1><p>這個指南將引導你在官方 Minecraft 啟動器上安裝 Fabric。</p><p>對於第三方啟動器，你應該參考它們的文件。</p><h2 id="1-download-the-fabric-installer" tabindex="-1">1. 下載 Fabric 安裝程式 <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. 下載 Fabric 安裝程式”">​</a></h2><p>你可以從 <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Fabric 官網</a>下載 Fabric 安裝程式。</p><p>如果你使用 Windows 作業系統，請下載 <code>.exe</code> 版本（<code>Download For Windows</code>），因為它不需要在你的系統上安裝 Java。 它改為使用官方啟動器附帶的 Java。</p><p>對於 macOS 和 Linux 使用者，你應該下載 <code>.jar</code> 版本。 有時，在進行這個步驟之前，你需要安裝 Java。</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. 執行 Fabric 安裝程式 <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. 執行 Fabric 安裝程式”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>在安裝前，請先關閉 Minecraft 和 Minecraft 啟動器。</p></div><details class="details custom-block"><summary>對於 macOS 使用者的資訊</summary><p>在 macOS 上，你可能需要在下載目錄中對 <code>.jar</code> 檔案按下右鍵，然後選擇 <code>打開</code> 才能執行它。</p><p>Fabric 安裝程式上的 macOS 右鍵選單</p><p>當詢問「你確定要打開它嗎？」時，請再次按下「打開」。</p></details><p>開啟安裝程式後，你應該會看到以下視窗：</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Fabric 安裝程式，「安裝」按鈕已醒目顯示" loading="lazy"></p><p>要安裝 Fabric，只需從下拉式選單中選擇你的遊戲版本，然後點選 <code>安裝</code>。</p><p><strong>確保已勾選「建立設定檔」。</strong></p><h2 id="3-you-re-done" tabindex="-1">3. 你完成了！ <a class="header-anchor" href="#3-you-re-done" aria-label="Permalink to “3. 你完成了！”">​</a></h2><p>安裝程式完成後，你可以開啟 Minecraft 啟動器，並從左下方的下拉式選單中選擇 Fabric 設定檔，然後按下「開始遊戲」！</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="選擇 Fabric 設定檔的 Minecraft 啟動器" loading="lazy"></p><p>現在你已經安裝了 Fabric，你可以將模組新增到你的遊戲中！ 參閱<a href="./finding-mods">尋找可信賴的模組</a>指南以取得更多資訊。</p><p>如果你在依照本指南操作時遇到任何問題，你可以在 <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord</a> 的 <code>#player-support</code> 頻道中尋求幫助。</p>`,19)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};